 269→// ============================================================================
 270→// Helpers
 271→// ============================================================================
 272→
 273→function extractConversationIdFromUrl(): string | null {
 274→  const appMatch = window.location.pathname.match(/\/app\/([^/?#]+)/);
 275→  if (appMatch?.[1]) return appMatch[1];
 276→  const gemMatch = window.location.pathname.match(/\/gem\/[^/]+\/([^/?#]+)/);
 277→  return gemMatch?.[1] || null;
 278→}
 279→
 280→function getConversationTitle(): string {
 281→  const conversationId = extractConversationIdFromUrl();
 282→  if (conversationId) {
 283→    const escapedId = conversationId.replace(/"/g, '\\"');
 284→    const link = document.querySelector<HTMLAnchorElement>(
 285→      `[data-test-id="conversation"][jslog*="c_${escapedId}"] a, a[href*="/app/${escapedId}"]`,
 286→    );
 287→    if (link?.textContent?.trim()) return link.textContent.trim();
 288→  }
 289→  return document.title || 'Untitled';
 290→}
 291→
 292→function ensureTurnId(el: HTMLElement, index: number): string {
 293→  const stableId = makeStableTurnId(index);
 294→  const current = el.dataset?.turnId || '';
 295→  if (normalizeTurnId(current) !== stableId) {
 296→    el.dataset.turnId = stableId;
 297→  }
 298→  return stableId;
 299→}
 300→
 301→function resolveUserMessageHost(userEl: HTMLElement): HTMLElement {
 302→  const preferred =
 303→    userEl.querySelector<HTMLElement>('.user-query-bubble-with-background') ||
 304→    userEl.querySelector<HTMLElement>('user-query-content .user-query-bubble-with-background') ||
 305→    userEl.querySelector<HTMLElement>('.user-query-bubble-container');
 306→  return preferred || userEl;
 307→}
 308→
 309→function findUserCopyButtonAnchor(userEl: HTMLElement): HTMLElement | null {
 310→  const copyButton =
 311→    userEl.querySelector<HTMLElement>('button[data-test-id="copy-button"]') ||
 312→    userEl
 313→      .querySelector<HTMLElement>(
 314→        'button mat-icon[fonticon="content_copy"], button mat-icon[data-mat-icon-name="content_copy"]',
 315→      )
 316→      ?.closest<HTMLElement>('button');
 317→
 318→  if (!copyButton) return null;
 319→  return copyButton.parentElement || copyButton;
 320→}
 321→
 322→function resolveForkButtonHost(userEl: HTMLElement): HTMLElement {
 323→  return findUserCopyButtonAnchor(userEl) || resolveUserMessageHost(userEl);
 324→}
 325→
 326→function extractConversationIdFromHref(href: string): string | null {
 327→  try {
 328→    const url = new URL(href, window.location.origin);
 329→    const appMatch = url.pathname.match(/\/app\/([^/?#]+)/);
 330→    if (appMatch?.[1]) return appMatch[1];
 331→    const gemMatch = url.pathname.match(/\/gem\/[^/]+\/([^/?#]+)/);
 332→    return gemMatch?.[1] || null;
 333→  } catch {
 334→    return null;
 335→  }
 336→}
 337→
 338→function findSidebarConversationLinkById(conversationId: string): HTMLAnchorElement | null {
 339→  const links = Array.from(
 340→    document.querySelectorAll<HTMLAnchorElement>('a[href*="/app/"], a[href*="/gem/"]'),
 341→  );
 342→  for (const link of links) {
 343→    if (extractConversationIdFromHref(link.href) === conversationId) return link;
 344→  }
 345→  return null;
 346→}
 347→
 348→function triggerNativeClick(target: HTMLElement): void {
 349→  const options = { bubbles: true, cancelable: true, view: window };
 350→  target.dispatchEvent(new MouseEvent('pointerdown', options));
 351→  target.dispatchEvent(new MouseEvent('mousedown', options));
 352→  target.dispatchEvent(new MouseEvent('mouseup', options));
 353→  target.dispatchEvent(new MouseEvent('click', options));
 354→}
 355→
 356→function navigateToForkConversation(node: ForkNode): void {
 357→  if (!node.conversationId) return;
 358→  const currentConversationId = extractConversationIdFromUrl();
 359→  if (currentConversationId === node.conversationId) return;
 360→
 361→  const sidebarLink = findSidebarConversationLinkById(node.conversationId);
 362→  if (sidebarLink) {
 363→    triggerNativeClick(sidebarLink);
 364→    return;
 365→  }
 366→
 367→  const fallbackUrl =
 368→    node.conversationUrl ||
 369→    `${window.location.origin}/app/${encodeURIComponent(node.conversationId)}`;
 370→  window.location.assign(fallbackUrl);
 371→}
 372→
 373→function collectSidebarConversationIds(): Set<string> {
 374→  const ids = new Set<string>();
 375→  const links = document.querySelectorAll<HTMLAnchorElement>('a[href*="/app/"], a[href*="/gem/"]');
 376→  links.forEach((link) => {
 377→    const id = extractConversationIdFromHref(link.href);
 378→    if (id) ids.add(id);
 379→  });
 380→  return ids;
 381→}
 382→
 383→async function getPreferredLanguage(): Promise<string | undefined> {
 384→  try {
 385→    const syncResult = await browser.storage.sync.get(StorageKeys.LANGUAGE);
 386→    const syncLanguage = syncResult?.[StorageKeys.LANGUAGE];
 387→    if (typeof syncLanguage === 'string' && syncLanguage.trim()) return syncLanguage;
 388→  } catch {
 389→    // Ignore sync storage failures.
 390→  }
 391→
 392→  try {
 393→    const localResult = await browser.storage.local.get(StorageKeys.LANGUAGE);
 394→    const localLanguage = localResult?.[StorageKeys.LANGUAGE];
 395→    if (typeof localLanguage === 'string' && localLanguage.trim()) return localLanguage;
 396→  } catch {
 397→    // Ignore local storage failures.
 398→  }
 399→
 400→  return undefined;
 401→}
 402→
 403→async function checkConversationExists(
 404→  node: ForkNode,
 405→  sidebarConversationIds: Set<string>,
 406→): Promise<boolean> {
 407→  const currentConversationId = extractConversationIdFromUrl();
 408→  if (currentConversationId && node.conversationId === currentConversationId) return true;
 409→  if (sidebarConversationIds.has(node.conversationId)) {
 410→    conversationExistenceCache.set(node.conversationId, { exists: true, checkedAt: Date.now() });
 411→    return true;
 412→  }
 413→
 414→  const cached = conversationExistenceCache.get(node.conversationId);
 415→  const now = Date.now();
 416→  if (cached && now - cached.checkedAt <= CONVERSATION_EXISTENCE_CACHE_TTL_MS) {
 417→    return cached.exists;
 418→  }
 419→
 420→  if (!node.conversationUrl) {
 421→    conversationExistenceCache.set(node.conversationId, { exists: false, checkedAt: now });
 422→    return false;
 423→  }
 424→
 425→  const controller = new AbortController();
 426→  const timer = setTimeout(() => controller.abort(), CONVERSATION_VERIFY_TIMEOUT_MS);
 427→  try {
 428→    const response = await fetch(node.conversationUrl, {
 429→      method: 'GET',
 430→      redirect: 'follow',
 431→      credentials: 'include',
 432→      signal: controller.signal,
 433→    });
 434→    const responseConversationId = extractConversationIdFromHref(response.url);
 435→    const exists =
 436→      response.ok && !!responseConversationId && node.conversationId === responseConversationId;
 437→    conversationExistenceCache.set(node.conversationId, { exists, checkedAt: now });
 438→    return exists;
 439→  } catch {
 440→    // If verification fails for network/CSP reasons, keep node to avoid destructive false positives.
 441→    return true;
 442→  } finally {
 443→    clearTimeout(timer);
 444→  }
 445→}
 446→
 447→async function pruneDeletedNodesFromGroup(
 448→  groupNodes: ForkNode[],
 449→  sidebarConversationIds: Set<string>,
 450→): Promise<ForkNode[]> {
 451→  const cleaned: ForkNode[] = [];
 452→
 453→  for (const node of groupNodes) {
 454→    const exists = await checkConversationExists(node, sidebarConversationIds);
 455→    if (exists) {
 456→      cleaned.push(node);
 457→      continue;
 458→    }
 459→
 460→    try {
 461→      await ForkNodesService.removeForkNode(node.conversationId, node.turnId, node.forkGroupId);
 462→    } catch (error) {
 463→      if (!isExtensionContextInvalidatedError(error)) {
 464→        console.error('[Fork] Failed to prune deleted fork node:', error);
 465→      }
 466→    }
 467→  }
 468→
 469→  return cleaned;
 470→}
 471→
 472→function clearInjectedForkIndicators(): void {
 473→  document.querySelectorAll(`.${FORK_INDICATOR_GROUP_CLASS}`).forEach((el) => el.remove());
 474→}
 475→
 476→function hasOrDedupForkIndicatorGroup(hostEl: HTMLElement): boolean {
 477→  const groups = Array.from(hostEl.querySelectorAll<HTMLElement>(`.${FORK_INDICATOR_GROUP_CLASS}`));
 478→  if (groups.length === 0) return false;
 479→  if (groups.length > 1) {
 480→    for (let i = 1; i < groups.length; i++) {
 481→      groups[i].remove();
 482→    }
 483→  }
 484→  return true;
 485→}
 486→
 487→/**
 488→ * Extract conversation content up to and including the given user turn index.
 489→ *
 490→ * Step 1: Extract turns 0..N with both user and assistant content when available.
 491→ * Step 2: Remove the last assistant response to let users continue from the last user turn.
 492→ */
 493→function extractConversationUpToTurn(userTurnIndex: number, sourceTurnId: string): string {
 494→  const pairs = collectForkChatPairs();
 495→  if (pairs.length === 0) return '';
 496→
 497→  const sourceIndex = pairs.findIndex(
 498→    (pair) => normalizeTurnId(pair.turnId) === normalizeTurnId(sourceTurnId),
 499→  );
 500→  const targetIndex = sourceIndex >= 0 ? sourceIndex : userTurnIndex;
 501→  const turns: ForkExtractedTurn[] = [];
 502→  for (let i = 0; i <= targetIndex && i < pairs.length; i++) {
 503→    turns.push({
 504→      user: pairs[i].user || '',
 505→      assistant: pairs[i].assistant || '',
 506→    });
 507→  }
 508→
 509→  return buildForkMarkdown(getConversationTitle(), turns, true);
 510→}
