 513→// Fork Button Injection
 514→// ============================================================================
 515→
 516→let observer: MutationObserver | null = null;
 517→let observerDebounceTimer: ReturnType<typeof setTimeout> | null = null;
 518→let storageRefreshTimer: ReturnType<typeof setTimeout> | null = null;
 519→let activeConfirm: HTMLElement | null = null;
 520→
 521→function dismissConfirm(): void {
 522→  if (activeConfirm) {
 523→    activeConfirm.remove();
 524→    activeConfirm = null;
 525→  }
 526→}
 527→
 528→function onDocumentClick(e: MouseEvent): void {
 529→  if (activeConfirm && !activeConfirm.contains(e.target as Node)) {
 530→    dismissConfirm();
 531→  }
 532→}
 533→
 534→function scheduleForkIndicatorRefresh(): void {
 535→  if (storageRefreshTimer) clearTimeout(storageRefreshTimer);
 536→  storageRefreshTimer = setTimeout(() => {
 537→    clearInjectedForkIndicators();
 538→    void injectForkIndicators();
 539→    storageRefreshTimer = null;
 540→  }, OBSERVER_DEBOUNCE_MS);
 541→}
 542→
 543→function injectForkButtons(): void {
 544→  const pairs = collectForkChatPairs();
 545→
 546→  pairs.forEach((pair, index) => {
 547→    const userEl = pair.userElement;
 548→    ensureTurnId(userEl, index);
 549→    const hostEl = resolveForkButtonHost(userEl);
 550→
 551→    const existingButton = userEl.querySelector<HTMLElement>(`.${FORK_BTN_CLASS}`);
 552→    if (existingButton) {
 553→      hostEl.style.position = hostEl.style.position || 'relative';
 554→      if (existingButton.parentElement !== hostEl) {
 555→        hostEl.appendChild(existingButton);
 556→      }
 557→      return;
 558→    }
 559→
 560→    const btn = document.createElement('button');
 561→    btn.className = FORK_BTN_CLASS;
 562→    btn.title = getTranslationSync('forkConversation');
 563→    btn.innerHTML = `${FORK_ICON}<span>${getTranslationSync('forkConversation')}</span>`;
 564→
 565→    btn.addEventListener('click', (e) => {
 566→      e.stopPropagation();
 567→      e.preventDefault();
 568→      showForkConfirmation(btn, userEl, index);
