 690→// ============================================================================
 691→// Pending Fork Handling (New Conversation)
 692→// ============================================================================
 693→
 694→interface PendingForkData {
 695→  sourceConversationId: string;
 696→  sourceTurnId: string;
 697→  sourceUrl: string;
 698→  sourceTitle: string;
 699→  forkGroupId: string;
 700→  sourceForkIndex: number;
 701→  nextForkIndex: number;
 702→  markdown: string;
 703→}
 704→
 705→function checkAndHandlePendingFork(): void {
 706→  const raw = sessionStorage.getItem(PENDING_FORK_KEY);
 707→  if (!raw) return;
 708→
 709→  let pendingFork: PendingForkData;
 710→  try {
 711→    const parsed = JSON.parse(raw) as Partial<PendingForkData>;
 712→    pendingFork = {
 713→      sourceConversationId: parsed.sourceConversationId || '',
 714→      sourceTurnId: parsed.sourceTurnId || '',
 715→      sourceUrl: parsed.sourceUrl || '',
 716→      sourceTitle: parsed.sourceTitle || '',
 717→      forkGroupId: parsed.forkGroupId || '',
 718→      sourceForkIndex: Number.isFinite(parsed.sourceForkIndex) ? parsed.sourceForkIndex! : 0,
 719→      nextForkIndex: Number.isFinite(parsed.nextForkIndex) ? parsed.nextForkIndex! : 1,
 720→      markdown: parsed.markdown || '',
 721→    };
 722→  } catch {
 723→    sessionStorage.removeItem(PENDING_FORK_KEY);
 724→    return;
 725→  }
 726→
 727→  if (
 728→    !pendingFork.sourceConversationId ||
 729→    !pendingFork.sourceTurnId ||
 730→    !pendingFork.forkGroupId ||
 731→    !pendingFork.markdown.trim()
 732→  ) {
 733→    sessionStorage.removeItem(PENDING_FORK_KEY);
 734→    return;
 735→  }
 736→
 737→  // Only handle on a new conversation page (no conversation ID yet)
 738→  const currentConvId = extractConversationIdFromUrl();
 739→  if (currentConvId) {
 740→    // Already in an existing conversation - this might be the result of a previous fork
 741→    sessionStorage.removeItem(PENDING_FORK_KEY);
 742→    return;
 743→  }
 744→
 745→  // Wait for the input field to be available
 746→  waitForElement('rich-textarea [contenteditable="true"]', 10000).then(async (input) => {
 747→    if (!input) {
 748→      console.warn('[Fork] Input field not found');
 749→      sessionStorage.removeItem(PENDING_FORK_KEY);
 750→      return;
 751→    }
 752→
 753→    // Paste the markdown content
 754→    input.focus();
 755→    try {
 756→      document.execCommand('insertText', false, pendingFork.markdown);
 757→    } catch {
 758→      // Fallback: set textContent
 759→      input.textContent = pendingFork.markdown;
 760→      input.dispatchEvent(new Event('input', { bubbles: true }));
 761→    }
 762→
 763→    // Clear pending fork from sessionStorage
 764→    sessionStorage.removeItem(PENDING_FORK_KEY);
 765→
 766→    // Watch for URL change (conversation created after submission)
 767→    watchForNewConversation(pendingFork);
 768→  });
 769→}
 770→
 771→function waitForElement(selector: string, timeoutMs: number): Promise<HTMLElement | null> {
 772→  return new Promise((resolve) => {
 773→    const existing = document.querySelector<HTMLElement>(selector);
 774→    if (existing && existing.getBoundingClientRect().height > 0) {
 775→      resolve(existing);
 776→      return;
 777→    }
 778→
 779→    const deadline = Date.now() + timeoutMs;
 780→    const check = () => {
 781→      const el = document.querySelector<HTMLElement>(selector);
 782→      if (el && el.getBoundingClientRect().height > 0) {
 783→        resolve(el);
 784→        return;
 785→      }
 786→      if (Date.now() > deadline) {
 787→        resolve(null);
 788→        return;
 789→      }
 790→      requestAnimationFrame(check);
 791→    };
 792→    requestAnimationFrame(check);
 793→  });
 794→}
 795→
 796→function watchForNewConversation(pendingFork: PendingForkData): void {
 797→  let lastUrl = window.location.href;
 798→
 799→  const checkUrl = async () => {
 800→    const currentUrl = window.location.href;
 801→    if (currentUrl === lastUrl) return;
 802→    lastUrl = currentUrl;
 803→
 804→    const newConvId = extractConversationIdFromUrl();
 805→    if (!newConvId) return;
 806→
 807→    // New conversation created! Create fork nodes for both sides
 808→    urlObserver.disconnect();
 809→
 810→    try {
 811→      // Create fork node for the SOURCE conversation (original, index 0)
 812→      const sourceNode: ForkNode = {
 813→        turnId: pendingFork.sourceTurnId,
 814→        conversationId: pendingFork.sourceConversationId,
 815→        conversationUrl: pendingFork.sourceUrl,
 816→        conversationTitle: pendingFork.sourceTitle,
 817→        forkGroupId: pendingFork.forkGroupId,
 818→        forkIndex: pendingFork.sourceForkIndex,
 819→        createdAt: Date.now(),
 820→      };
 821→      await ForkNodesService.addForkNode(sourceNode);
 822→
 823→      // Create fork node for the NEW conversation (fork)
 824→      // Use the first user turn ID in the new conversation
 825→      const newNode: ForkNode = {
 826→        turnId: 'u-0', // First user turn in new conversation
 827→        conversationId: newConvId,
 828→        conversationUrl: currentUrl,
 829→        conversationTitle: getConversationTitle(),
 830→        forkGroupId: pendingFork.forkGroupId,
 831→        forkIndex: pendingFork.nextForkIndex,
 832→        createdAt: Date.now(),
 833→      };
 834→      await ForkNodesService.addForkNode(newNode);
 835→
 836→      // Inject fork indicators in the new conversation
 837→      setTimeout(() => injectForkIndicators(), 1000);
 838→    } catch (error) {
 839→      if (!isExtensionContextInvalidatedError(error)) {
 840→        console.error('[Fork] Failed to create fork nodes:', error);
 841→      }
 842→    }
 843→  };
 844→
 845→  // Use a MutationObserver on the URL (via popstate + polling)
 846→  const urlObserver = new MutationObserver(() => void checkUrl());
 847→  urlObserver.observe(document, { subtree: true, childList: true });
 848→
 849→  // Also listen to popstate and hashchange
 850→  const onUrlChange = () => void checkUrl();
 851→  window.addEventListener('popstate', onUrlChange);
 852→  window.addEventListener('hashchange', onUrlChange);
 853→
 854→  // Poll as fallback (SPA navigation may not trigger popstate)
 855→  const pollInterval = setInterval(() => {
 856→    void checkUrl();
 857→  }, 500);
 858→
 859→  // Cleanup after 60 seconds
 860→  setTimeout(() => {
 861→    urlObserver.disconnect();
 862→    window.removeEventListener('popstate', onUrlChange);
 863→    window.removeEventListener('hashchange', onUrlChange);
 864→    clearInterval(pollInterval);
 865→  }, 60000);
 866→}
