 872→async function injectForkIndicators(): Promise<void> {
 873→  const conversationId = extractConversationIdFromUrl();
 874→  if (!conversationId) return;
 875→
 876→  let forkNodes: ForkNode[];
 877→  try {
 878→    forkNodes = await ForkNodesService.getForConversation(conversationId);
 879→  } catch (error) {
 880→    if (!isExtensionContextInvalidatedError(error)) {
 881→      console.error('[Fork] Failed to get fork nodes:', error);
 882→    }
 883→    return;
 884→  }
 885→
 886→  if (forkNodes.length === 0) return;
 887→
 888→  // Build a map of normalized turnId -> forkGroupIds
 889→  const turnForkMap = new Map<string, Set<string>>();
 890→  for (const node of forkNodes) {
 891→    const normalizedTurnId = normalizeTurnId(node.turnId);
 892→    if (!turnForkMap.has(normalizedTurnId)) {
 893→      turnForkMap.set(normalizedTurnId, new Set<string>());
 894→    }
 895→    turnForkMap.get(normalizedTurnId)?.add(node.forkGroupId);
 896→  }
 897→
 898→  const pairs = collectForkChatPairs();
 899→  const sidebarConversationIds = collectSidebarConversationIds();
 900→  if (conversationId) sidebarConversationIds.add(conversationId);
 901→
 902→  for (let index = 0; index < pairs.length; index++) {
 903→    const userEl = pairs[index].userElement;
 904→    const turnId = normalizeTurnId(ensureTurnId(userEl, index));
 905→    const hostEl = resolveUserMessageHost(userEl);
 906→    const forkGroupIds = turnForkMap.get(turnId);
 907→    if (!forkGroupIds || forkGroupIds.size === 0) continue;
 908→
 909→    if (hasOrDedupForkIndicatorGroup(hostEl)) continue;
 910→
 911→    const groupNodesList: ForkNode[][] = [];
 912→    for (const forkGroupId of forkGroupIds) {
 913→      try {
 914→        const groupNodes = await ForkNodesService.getGroup(forkGroupId);
 915→        if (groupNodes.length === 0) continue;
 916→        const cleanedGroupNodes = await pruneDeletedNodesFromGroup(
 917→          groupNodes,
 918→          sidebarConversationIds,
 919→        );
 920→        if (cleanedGroupNodes.length > 0) groupNodesList.push(cleanedGroupNodes);
 921→      } catch {
 922→        // Ignore single group failure and continue rendering available groups.
 923→      }
 924→    }
 925→    if (groupNodesList.length === 0) continue;
 926→
 927→    const displayNodes = buildBranchDisplayNodes(groupNodesList);
 928→    if (displayNodes.length < 2) continue;
 929→
 930→    // Re-check after async group loading to avoid duplicate render in concurrent injections.
 931→    if (hasOrDedupForkIndicatorGroup(hostEl)) continue;
 932→
 933→    const group = document.createElement('div');
 934→    group.className = FORK_INDICATOR_GROUP_CLASS;
 935→
 936→    for (let displayIndex = 0; displayIndex < displayNodes.length; displayIndex++) {
 937→      const node = displayNodes[displayIndex];
 938→      const branchNumber = displayIndex + 1;
 939→      const isCurrent = node.conversationId === conversationId;
 940→      const item = document.createElement('div');
 941→      item.className = FORK_INDICATOR_ITEM_CLASS;
 942→
 943→      const indicator = document.createElement('button');
 944→      indicator.className = `${FORK_INDICATOR_CLASS}${isCurrent ? ' gv-current' : ''}`;
 945→      indicator.type = 'button';
 946→      indicator.textContent = String(branchNumber);
 947→      indicator.title = `${getTranslationSync('forkBranch')} ${branchNumber}${
 948→        isCurrent ? ` - ${getTranslationSync('forkCurrent')}` : ''
 949→      }`;
 950→
 951→      if (isCurrent) {
 952→        indicator.setAttribute('aria-current', 'true');
 953→        indicator.disabled = true;
 954→      } else {
 955→        indicator.addEventListener('click', (e) => {
 956→          e.stopPropagation();
 957→          e.preventDefault();
 958→          navigateToForkConversation(node);
 959→        });
 960→      }
 961→      item.appendChild(indicator);
 962→
 963→      const deleteBtn = document.createElement('button');
 964→      deleteBtn.className = FORK_INDICATOR_DELETE_CLASS;
 965→      deleteBtn.type = 'button';
 966→      deleteBtn.textContent = '×';
 967→      deleteBtn.title = getTranslationSync('forkDeleteData');
 968→      deleteBtn.setAttribute('aria-label', getTranslationSync('forkDeleteData'));
 969→      deleteBtn.addEventListener('click', async (e) => {
 970→        e.stopPropagation();
 971→        e.preventDefault();
 972→        const confirmed = window.confirm(getTranslationSync('forkDeleteDataConfirm'));
 973→        if (!confirmed) return;
 974→
 975→        deleteBtn.disabled = true;
 976→        try {
 977→          await ForkNodesService.removeForkNode(node.conversationId, node.turnId, node.forkGroupId);
 978→        } catch (error) {
 979→          if (!isExtensionContextInvalidatedError(error)) {
 980→            console.error('[Fork] Failed to delete fork branch data:', error);
 981→          }
 982→        } finally {
 983→          clearInjectedForkIndicators();
 984→          void injectForkIndicators();
 985→        }
 986→      });
 987→      item.appendChild(deleteBtn);
 988→      group.appendChild(item);
 989→    }
 990→
 991→    hostEl.style.position = hostEl.style.position || 'relative';
 992→    hostEl.appendChild(group);
 993→  }
 994→}
