1030→export function startFork(): () => void {
1031→  injectStyles();
1032→
1033→  // Check for pending fork data (new conversation paste)
1034→  checkAndHandlePendingFork();
1035→
1036→  // Inject fork buttons and indicators
1037→  const setup = () => {
1038→    injectForkButtons();
1039→    void injectForkIndicators();
1040→  };
1041→
1042→  // Initial injection with delay to let DOM settle
1043→  setTimeout(setup, 1000);
1044→
1045→  // MutationObserver for dynamically loaded messages
1046→  observer = new MutationObserver(() => {
1047→    if (observerDebounceTimer) clearTimeout(observerDebounceTimer);
1048→    observerDebounceTimer = setTimeout(() => {
1049→      injectForkButtons();
1050→      void injectForkIndicators();
1051→    }, OBSERVER_DEBOUNCE_MS);
1052→  });
1053→
1054→  observer.observe(document.body, {
1055→    childList: true,
1056→    subtree: true,
1057→  });
1058→
1059→  // Dismiss confirm dialog on click outside
1060→  document.addEventListener('click', onDocumentClick);
1061→
1062→  // Language change listener
1063→  const onStorageChanged = (
1064→    changes: Record<string, browser.Storage.StorageChange>,
1065→    areaName: string,
1066→  ) => {
1067→    if ((areaName === 'sync' || areaName === 'local') && changes[StorageKeys.LANGUAGE]) {
1068→      updateForkButtonTexts();
1069→    }
1070→    if (areaName === 'local' && changes[StorageKeys.FORK_NODES]) {
1071→      scheduleForkIndicatorRefresh();
1072→    }
1073→  };
1074→  browser.storage.onChanged.addListener(onStorageChanged);
1075→
1076→  // Cleanup function
1077→  return () => {
1078→    if (observer) {
1079→      observer.disconnect();
1080→      observer = null;
1081→    }
1082→    if (observerDebounceTimer) {
1083→      clearTimeout(observerDebounceTimer);
1084→      observerDebounceTimer = null;
1085→    }
1086→    if (storageRefreshTimer) {
1087→      clearTimeout(storageRefreshTimer);
1088→      storageRefreshTimer = null;
1089→    }
1090→    dismissConfirm();
1091→    document.removeEventListener('click', onDocumentClick);
1092→    browser.storage.onChanged.removeListener(onStorageChanged);
1093→
1094→    // Remove injected elements
1095→    document.querySelectorAll(`.${FORK_BTN_CLASS}`).forEach((el) => el.remove());
1096→    document.querySelectorAll(`.${FORK_INDICATOR_CLASS}`).forEach((el) => el.remove());
1097→    document.querySelectorAll(`.${FORK_INDICATOR_GROUP_CLASS}`).forEach((el) => el.remove());
1098→    const style = document.getElementById(STYLE_ID);
1099→    if (style) style.remove();
1100→  };
1101→}
