 1→/**
 2→ * ForkNodesService - communicates with background script for fork node persistence
 3→ * Follows the same pattern as StarredMessagesService
 4→ */
 5→import { eventBus } from '../timeline/EventBus';
 6→import type { ForkNode, ForkNodesData } from './forkTypes';
 7→
 8→async function sendMessage<T>(type: string, payload?: unknown): Promise<T> {
 9→  return new Promise((resolve, reject) => {
10→    try {
11→      chrome.runtime.sendMessage({ type, payload }, (response) => {
12→        if (chrome.runtime.lastError) {
13→          reject(new Error(chrome.runtime.lastError.message));
14→          return;
15→        }
16→        if (response?.ok) {
17→          resolve(response as T);
18→        } else {
19→          reject(new Error(response?.error || 'Unknown error'));
20→        }
21→      });
22→    } catch (error) {
23→      reject(error);
24→    }
25→  });
26→}
27→
28→export class ForkNodesService {
29→  static async addForkNode(node: ForkNode): Promise<boolean> {
30→    const response = await sendMessage<{ ok: boolean; added: boolean }>('gv.fork.add', node);
31→    if (response.added) {
32→      eventBus.emit('fork:added', {
33→        conversationId: node.conversationId,
34→        turnId: node.turnId,
35→        forkGroupId: node.forkGroupId,
36→      });
37→    }
38→    return response.added;
39→  }
40→
41→  static async removeForkNode(
42→    conversationId: string,
43→    turnId: string,
44→    forkGroupId: string,
45→  ): Promise<boolean> {
46→    const response = await sendMessage<{ ok: boolean; removed: boolean }>('gv.fork.remove', {
47→      conversationId,
48→      turnId,
49→      forkGroupId,
50→    });
51→    if (response.removed) {
52→      eventBus.emit('fork:removed', { conversationId, turnId, forkGroupId });
53→    }
54→    return response.removed;
55→  }
