 1→import type { ForkNode } from './forkTypes';
 2→import { normalizeTurnId } from './turnId';
 3→
 4→export interface ForkPlan {
 5→  forkGroupId: string;
 6→  sourceForkIndex: number;
 7→  nextForkIndex: number;
 8→}
 9→
10→export function resolveForkPlan(
11→  conversationId: string,
12→  turnId: string,
13→  conversationNodes: ForkNode[],
14→  groups: Record<string, ForkNode[]>,
15→  createForkGroupId: () => string,
16→): ForkPlan {
17→  const normalizedTurnId = normalizeTurnId(turnId);
18→  const sameTurnNodes = conversationNodes.filter(
19→    (node) => normalizeTurnId(node.turnId) === normalizedTurnId,
20→  );
21→
22→  if (sameTurnNodes.length === 0) {
23→    return {
24→      forkGroupId: createForkGroupId(),
25→      sourceForkIndex: 0,
26→      nextForkIndex: 1,
27→    };
28→  }
29→
30→  const groupIds = Array.from(new Set(sameTurnNodes.map((node) => node.forkGroupId)));
31→  let bestGroupId = groupIds[0];
32→  let bestGroupNodes = groups[bestGroupId] || [];
33→
34→  for (const groupId of groupIds) {
35→    const groupNodes = groups[groupId] || [];
36→    if (groupNodes.length > bestGroupNodes.length) {
37→      bestGroupId = groupId;
38→      bestGroupNodes = groupNodes;
39→    }
40→  }
41→
42→  const sourceNode = bestGroupNodes.find(
43→    (node) =>
44→      node.conversationId === conversationId && normalizeTurnId(node.turnId) === normalizedTurnId,
45→  );
46→  const maxForkIndex = bestGroupNodes.reduce((max, node) => Math.max(max, node.forkIndex), 0);
47→
48→  return {
49→    forkGroupId: bestGroupId,
50→    sourceForkIndex: sourceNode?.forkIndex ?? 0,
51→    nextForkIndex: maxForkIndex + 1,
52→  };
53→}
54→
55→export function buildBranchDisplayNodes(groupNodesList: ForkNode[][]): ForkNode[] {
56→  const dedupedByConversation = new Map<string, ForkNode>();
57→
58→  for (const node of groupNodesList.flat()) {
59→    const existing = dedupedByConversation.get(node.conversationId);
60→    if (!existing) {
61→      dedupedByConversation.set(node.conversationId, node);
62→      continue;
63→    }
64→
65→    if (node.forkIndex < existing.forkIndex) {
66→      dedupedByConversation.set(node.conversationId, node);
67→      continue;
68→    }
69→
70→    if (node.forkIndex === existing.forkIndex && node.createdAt < existing.createdAt) {
71→      dedupedByConversation.set(node.conversationId, node);
72→    }
73→  }
74→
75→  return Array.from(dedupedByConversation.values()).sort((a, b) => {
76→    if (a.forkIndex !== b.forkIndex) return a.forkIndex - b.forkIndex;
77→    return a.createdAt - b.createdAt;
78→  });
79→}
