  9→export interface ForkChatPair {
 10→  turnId: string;
 11→  user: string;
 12→  assistant: string;
 13→  userElement: HTMLElement;
 14→}
 15→
 16→function normalizeText(text: string | null): string {
 17→  if (!text) return '';
 18→  return text.replace(/\s+/g, ' ').trim();
 19→}
 20→
 21→function queryOutsideThoughts<T extends Element = Element>(
 22→  root: Element,
 23→  selector: string,
 24→): T | null {
 25→  const candidates = root.querySelectorAll<T>(selector);
 26→  for (const el of Array.from(candidates)) {
 27→    if (!el.closest('model-thoughts, .thoughts-container, .thoughts-content')) {
 28→      return el;
 29→    }
 30→  }
 31→  return null;
 32→}
 33→
 34→function filterTopLevel(elements: Element[]): HTMLElement[] {
 35→  const arr = elements.map((element) => element as HTMLElement);
 36→  const out: HTMLElement[] = [];
 37→  for (let i = 0; i < arr.length; i++) {
 38→    const el = arr[i];
 39→    let isDescendant = false;
 40→    for (let j = 0; j < arr.length; j++) {
 41→      if (i === j) continue;
 42→      const other = arr[j];
 43→      if (other.contains(el)) {
 44→        isDescendant = true;
 45→        break;
 46→      }
 47→    }
 48→    if (!isDescendant) out.push(el);
 49→  }
 50→  return out;
 51→}
 52→
 53→function dedupeByTextAndOffset(elements: HTMLElement[], firstTurnOffset: number): HTMLElement[] {
 54→  const seen = new Set<string>();
 55→  const out: HTMLElement[] = [];
 56→  for (const el of elements) {
 57→    const offsetFromStart = (el.offsetTop || 0) - firstTurnOffset;
 58→    const key = `${normalizeText(el.textContent || '')}|${Math.round(offsetFromStart)}`;
 59→    if (seen.has(key)) continue;
 60→    seen.add(key);
 61→    out.push(el);
 62→  }
 63→  return out;
 64→}
 65→
 66→function getUserSelectors(): string[] {
 67→  const configured = (() => {
 68→    try {
 69→      return (
 70→        localStorage.getItem('geminiTimelineUserTurnSelector') ||
 71→        localStorage.getItem('geminiTimelineUserTurnSelectorAuto') ||
 72→        ''
 73→      );
 74→    } catch {
 75→      return '';
 76→    }
 77→  })();
 78→
 79→  const defaults = [
 80→    '.user-query-bubble-with-background',
 81→    '.user-query-bubble-container',
 82→    '.user-query-container',
 83→    'user-query-content .user-query-bubble-with-background',
 84→    'div[aria-label="User message"]',
 85→    'article[data-author="user"]',
 86→    'article[data-turn="user"]',
 87→    '[data-message-author-role="user"]',
 88→    'div[role="listitem"][data-user="true"]',
 89→  ];
 90→  return configured
 91→    ? [configured, ...defaults.filter((selector) => selector !== configured)]
 92→    : defaults;
 93→}
 94→
 95→function getAssistantSelectors(): string[] {
 96→  return [
 97→    '[aria-label="Gemini response"]',
 98→    '[data-message-author-role="assistant"]',
 99→    '[data-message-author-role="model"]',
100→    'article[data-author="assistant"]',
101→    'article[data-turn="assistant"]',
102→    'article[data-turn="model"]',
103→    '.model-response, model-response',
104→    '.response-container',
105→    'div[role="listitem"]:not([data-user="true"])',
106→  ];
107→}
108→
109→function pickAssistantExportElement(assistantHost: HTMLElement): HTMLElement {
110→  return (
111→    queryOutsideThoughts<HTMLElement>(assistantHost, 'message-content') ||
112→    queryOutsideThoughts<HTMLElement>(assistantHost, '.markdown, .markdown-main-panel') ||
113→    (assistantHost.closest('.presented-response-container') as HTMLElement | null) ||
114→    queryOutsideThoughts<HTMLElement>(
115→      assistantHost,
116→      '.presented-response-container, .response-content',
117→    ) ||
118→    queryOutsideThoughts<HTMLElement>(assistantHost, 'response-element') ||
119→    assistantHost
120→  );
121→}
122→
123→export function collectForkChatPairs(): ForkChatPair[] {
124→  const userSelectors = getUserSelectors();
125→  const assistantSelectors = getAssistantSelectors();
126→  const root = resolveConversationRoot({ userSelectors, doc: document });
127→
128→  const userNodesRaw = filterOutDeepResearchImmersiveNodes(
129→    Array.from(root.querySelectorAll<HTMLElement>(userSelectors.join(','))),
130→  );
131→  if (userNodesRaw.length === 0) return [];
132→
133→  let users = filterTopLevel(userNodesRaw);
134→  if (users.length === 0) return [];
135→
136→  const firstOffset = users[0].offsetTop || 0;
137→  users = dedupeByTextAndOffset(users, firstOffset);
138→  const userOffsets = users.map((el) => el.offsetTop || 0);
139→
140→  const assistantNodesRaw = filterOutDeepResearchImmersiveNodes(
141→    Array.from(root.querySelectorAll<HTMLElement>(assistantSelectors.join(','))),
142→  );
143→  const assistants = filterTopLevel(assistantNodesRaw);
144→  const assistantOffsets = assistants.map((el) => el.offsetTop || 0);
145→
146→  const pairs: ForkChatPair[] = [];
147→
148→  for (let i = 0; i < users.length; i++) {
149→    const userEl = users[i];
150→    const turnId = makeStableTurnId(i);
151→    userEl.dataset.turnId = turnId;
152→
153→    const userExtracted = DOMContentExtractor.extractUserContent(userEl).text;
154→    const userText = userExtracted || normalizeText(userEl.innerText || userEl.textContent || '');
155→
156→    const start = userOffsets[i];
157→    const end = i + 1 < userOffsets.length ? userOffsets[i + 1] : Number.POSITIVE_INFINITY;
158→
159→    let assistantHost: HTMLElement | null = null;
160→    let bestOff = Number.POSITIVE_INFINITY;
161→
162→    for (let k = 0; k < assistants.length; k++) {
163→      const off = assistantOffsets[k];
164→      if (off >= start && off < end && off < bestOff) {
165→        bestOff = off;
166→        assistantHost = assistants[k];
167→      }
168→    }
169→
170→    if (!assistantHost) {
171→      let sib: HTMLElement | null = userEl;
172→      for (let step = 0; step < 8 && sib; step++) {
173→        sib = sib.nextElementSibling as HTMLElement | null;
174→        if (!sib) break;
175→        if (sib.matches(userSelectors.join(','))) break;
176→        if (sib.matches(assistantSelectors.join(','))) {
177→          assistantHost = sib;
178→          break;
179→        }
180→      }
181→    }
182→
183→    let assistantText = '';
184→    if (assistantHost) {
185→      const assistantExportEl = pickAssistantExportElement(assistantHost);
186→      const extracted = DOMContentExtractor.extractAssistantContent(assistantExportEl).text;
187→      assistantText =
188→        extracted ||
189→        normalizeText(assistantExportEl.innerText || assistantExportEl.textContent || '');
190→    }
191→
192→    if (userText || assistantText) {
193→      pairs.push({
194→        turnId,
195→        user: userText,
196→        assistant: assistantText,
197→        userElement: userEl,
198→      });
199→    }
200→  }
201→
202→  return pairs;
203→}
