 1→export interface ForkExtractedTurn {
 2→  user: string;
 3→  assistant?: string;
 4→}
 5→
 6→export function buildForkMarkdown(
 7→  title: string,
 8→  turns: ForkExtractedTurn[],
 9→  dropLastAssistant: boolean,
10→): string {
11→  if (!turns.length) return '';
12→
13→  const normalizedTurns = turns.map((turn) => ({ ...turn }));
14→  if (dropLastAssistant && normalizedTurns.length > 0) {
15→    normalizedTurns[normalizedTurns.length - 1].assistant = '';
16→  }
17→
18→  const lines: string[] = [];
19→  lines.push(`# ${title || 'Untitled'}`);
20→  lines.push('');
21→
22→  for (const turn of normalizedTurns) {
23→    lines.push('### 👤 User');
24→    lines.push('');
25→    lines.push(turn.user || '');
26→    lines.push('');
27→
28→    if (turn.assistant?.trim()) {
29→      lines.push('### 🤖 Assistant');
30→      lines.push('');
31→      lines.push(turn.assistant);
32→      lines.push('');
33→    }
34→  }
35→
36→  return lines.join('\n');
37→}
