 1→const USER_TURN_ID_RE = /^u-(\d+)(?:-.+)?$/;
 2→
 3→export function makeStableTurnId(index: number): string {
 4→  return `u-${Math.max(0, index)}`;
 5→}
 6→
 7→export function normalizeTurnId(turnId: string): string {
 8→  const trimmed = turnId.trim();
 9→  const match = USER_TURN_ID_RE.exec(trimmed);
10→  if (!match) return trimmed;
11→  return `u-${match[1]}`;
12→}
