 29→function isSyncAccountScope(value: unknown): value is SyncAccountScope {
 30→  if (typeof value !== 'object' || value === null) return false;
 31→  const scope = value as Record<string, unknown>;
 32→  return (
 33→    typeof scope.accountKey === 'string' &&
 34→    typeof scope.accountId === 'number' &&
 35→    Number.isFinite(scope.accountId) &&
 36→    (typeof scope.routeUserId === 'string' || scope.routeUserId === null)
 37→  );
 38→}
