 40→function toSyncAccountScope(scope: AccountScope): SyncAccountScope {
 41→  return {
 42→    accountKey: scope.accountKey,
 43→    accountId: scope.accountId,
 44→    routeUserId: scope.routeUserId,
 45→  };
 46→}
