 48→async function resolveAccountScopeForMessage(
 49→  sender: chrome.runtime.MessageSender,
 50→  platform: AccountPlatform,
 51→  explicitScope?: SyncAccountScope,
 52→): Promise<SyncAccountScope | null> {
 53→  const enabled = await accountIsolationService.isIsolationEnabled({
 54→    platform,
 55→    pageUrl: sender.tab?.url ?? null,
 56→  });
 57→  if (!enabled) return null;
 58→  if (explicitScope) return explicitScope;
 59→
 60→  const resolved = await accountIsolationService.resolveAccountScope({
 61→    pageUrl: sender.tab?.url ?? null,
 62→  });
 63→  return toSyncAccountScope(resolved);
