 66→function matchesRouteScope(url: string, routeUserId: string | null): boolean {
 67→  if (!routeUserId) return true;
 68→  const routeFromUrl = extractRouteUserIdFromUrl(url);
 69→  return routeFromUrl === null || routeFromUrl === routeUserId;
 70→}
 71→
 72→function filterStarredByRouteScope(
 73→  data: StarredMessagesData,
 74→  routeUserId: string | null,
 75→): StarredMessagesData {
 76→  if (!routeUserId) return data;
 77→
 78→  const filteredEntries = Object.entries(data.messages).map(([conversationId, messages]) => {
 79→    const filteredMessages = messages.filter((message) =>
 80→      matchesRouteScope(message.conversationUrl, routeUserId),
 81→    );
 82→    return [conversationId, filteredMessages] as const;
 83→  });
 84→
 85→  const filteredMessages = Object.fromEntries(
 86→    filteredEntries.filter((entry) => entry[1].length > 0),
 87→  );
 88→  return { messages: filteredMessages };
 89→}
 90→
 91→function filterForkNodesByRouteScope(
 92→  data: ForkNodesData,
 93→  routeUserId: string | null,
 94→): ForkNodesData {
 95→  if (!routeUserId) return data;
 96→
 97→  const filteredNodes: Record<string, ForkNode[]> = {};
 98→  for (const [conversationId, nodes] of Object.entries(data.nodes)) {
 99→    const filtered = nodes.filter((node) => matchesRouteScope(node.conversationUrl, routeUserId));
100→    if (filtered.length > 0) {
101→      filteredNodes[conversationId] = filtered;
102→    }
103→  }
104→
105→  const filteredGroups: Record<string, string[]> = {};
106→  for (const nodes of Object.values(filteredNodes)) {
107→    for (const node of nodes) {
108→      if (!filteredGroups[node.forkGroupId]) {
109→        filteredGroups[node.forkGroupId] = [];
110→      }
111→      const key = `${node.conversationId}:${node.turnId}`;
112→      if (!filteredGroups[node.forkGroupId].includes(key)) {
113→        filteredGroups[node.forkGroupId].push(key);
114→      }
115→    }
116→  }
117→
118→  return {
119→    nodes: filteredNodes,
120→    groups: filteredGroups,
121→  };
122→}
