165→const MANIFEST_DEFAULT_DOMAINS = new Set(
166→  [
167→    ...(chrome.runtime.getManifest().host_permissions || []),
168→    ...(chrome.runtime.getManifest().content_scripts?.flatMap((c) => c.matches || []) || []),
169→  ]
170→    .map(patternToDomain)
171→    .filter((d): d is string => !!d),
172→);
173→
174→function patternToDomain(pattern: string | undefined): string | null {
175→  if (!pattern) return null;
176→  try {
177→    const withoutScheme = pattern.replace(/^[^:]+:\/\//, '');
178→    const hostPart = withoutScheme.replace(/\/.*$/, '').replace(/^\*\./, '');
179→    return hostPart || null;
180→  } catch {
181→    return null;
182→  }
183→}
184→
185→function toMatchPatterns(domain: string): string[] {
186→  const normalized = domain
187→    .trim()
188→    .toLowerCase()
189→    .replace(/^https?:\/\//, '')
190→    .replace(/^www\./, '')
191→    .replace(/\/.*$/, '')
192→    .replace(/^\*\./, '');
193→
194→  if (!normalized) return [];
195→  return [`https://*.${normalized}/*`, `http://*.${normalized}/*`];
196→}
197→
198→function extractDomainsFromOrigins(origins?: string[]): string[] {
199→  if (!Array.isArray(origins)) return [];
200→  const domains = origins
201→    .map(patternToDomain)
202→    .filter((d): d is string => !!d)
203→    .filter((d) => !MANIFEST_DEFAULT_DOMAINS.has(d));
204→  return Array.from(new Set(domains));
205→}
206→
207→async function filterGrantedOrigins(patterns: string[]): Promise<string[]> {
208→  const granted: string[] = [];
209→
210→  for (const origin of patterns) {
211→    try {
212→      const hasPermission = await browser.permissions.contains({ origins: [origin] });
213→      if (hasPermission) {
214→        granted.push(origin);
215→      }
216→    } catch (error) {
217→      console.warn('[Background] Failed to check permission for', origin, error);
218→    }
219→  }
220→
221→  return granted;
222→}
223→
224→async function syncCustomContentScripts(domains?: string[]): Promise<void> {
225→  if (!chrome.scripting?.registerContentScripts) return;
226→
227→  const manifestContentScript = chrome.runtime.getManifest().content_scripts?.[0];
228→  if (!manifestContentScript) return;
229→
230→  const domainList =
231→    domains ??
232→    (
233→      await chrome.storage.sync.get({
234→        [CUSTOM_WEBSITE_KEY]: [],
235→      })
236→    )[CUSTOM_WEBSITE_KEY];
237→
238→  const matchPatterns = Array.from(
239→    new Set((Array.isArray(domainList) ? domainList : []).flatMap(toMatchPatterns).filter(Boolean)),
240→  );
241→
242→  const grantedMatches = await filterGrantedOrigins(matchPatterns);
243→
244→  try {
245→    await chrome.scripting.unregisterContentScripts({ ids: [CUSTOM_CONTENT_SCRIPT_ID] });
246→  } catch {
247→    // No-op if script was not registered
248→  }
249→
250→  if (!grantedMatches.length) return;
251→
252→  const runAt =
253→    manifestContentScript.run_at === 'document_start'
254→      ? 'document_start'
255→      : manifestContentScript.run_at === 'document_end'
256→        ? 'document_end'
257→        : 'document_idle';
258→
259→  try {
260→    await chrome.scripting.registerContentScripts([
261→      {
262→        id: CUSTOM_CONTENT_SCRIPT_ID,
263→        js: manifestContentScript.js || [],
264→        css: manifestContentScript.css,
265→        matches: grantedMatches,
266→        allFrames: manifestContentScript.all_frames,
267→        runAt,
268→        persistAcrossSessions: true,
269→      },
270→    ]);
271→    console.log('[Background] Custom content scripts registered for', grantedMatches);
272→  } catch (error) {
273→    console.error('[Background] Failed to register custom content scripts:', error);
274→  }
275→}
