277→// Initial sync for persisted permissions
278→void syncCustomContentScripts();
279→
280→// Initial fetch interceptor registration
281→void registerFetchInterceptor();
282→
283→chrome.storage.onChanged.addListener((changes, areaName) => {
284→  if (areaName !== 'sync') return;
285→
286→  if (Object.prototype.hasOwnProperty.call(changes, CUSTOM_WEBSITE_KEY)) {
287→    const newValue = changes[CUSTOM_WEBSITE_KEY]?.newValue;
288→    const domains = Array.isArray(newValue) ? newValue : [];
289→    void syncCustomContentScripts(domains);
290→  }
291→
292→  // Re-register fetch interceptor when watermark remover setting changes
293→  if (Object.prototype.hasOwnProperty.call(changes, 'geminiWatermarkRemoverEnabled')) {
294→    void registerFetchInterceptor();
295→  }
