324→/**
325→ * Centralized starred messages management to prevent race conditions.
326→ * All read-modify-write operations are serialized through this background script.
327→ */
328→class StarredMessagesManager {
329→  private operationQueue: Promise<unknown> = Promise.resolve();
330→
331→  /**
332→   * Serialize all operations to prevent race conditions
333→   */
334→  private serialize<T>(operation: () => Promise<T>): Promise<T> {
335→    const promise = this.operationQueue.then(operation, operation);
336→    this.operationQueue = promise.catch(() => {}); // Prevent error propagation
337→    return promise;
338→  }
339→
340→  private async getFromStorage(): Promise<StarredMessagesData> {
341→    try {
342→      const result = await chrome.storage.local.get([StorageKeys.TIMELINE_STARRED_MESSAGES]);
343→      return result[StorageKeys.TIMELINE_STARRED_MESSAGES] || { messages: {} };
344→    } catch (error) {
345→      console.error('[Background] Failed to get starred messages:', error);
346→      return { messages: {} };
347→    }
348→  }
349→
350→  private async saveToStorage(data: StarredMessagesData): Promise<void> {
351→    await chrome.storage.local.set({ [StorageKeys.TIMELINE_STARRED_MESSAGES]: data });
352→  }
353→
354→  async addStarredMessage(message: StarredMessage): Promise<boolean> {
355→    return this.serialize(async () => {
356→      const data = await this.getFromStorage();
357→
358→      if (!data.messages[message.conversationId]) {
359→        data.messages[message.conversationId] = [];
360→      }
361→
362→      // Check if message already exists
363→      const exists = data.messages[message.conversationId].some((m) => m.turnId === message.turnId);
364→
365→      if (!exists) {
366→        // Truncate content to save storage space
367→        // Popup is ~360px wide with line-clamp-2, showing ~50-60 chars max
368→        const MAX_CONTENT_LENGTH = 60;
369→        const truncatedMessage: StarredMessage = {
370→          ...message,
371→          content:
372→            message.content.length > MAX_CONTENT_LENGTH
373→              ? message.content.slice(0, MAX_CONTENT_LENGTH) + '...'
374→              : message.content,
375→        };
376→        data.messages[message.conversationId].push(truncatedMessage);
377→        await this.saveToStorage(data);
378→        return true;
379→      }
380→      return false;
381→    });
382→  }
383→
384→  async removeStarredMessage(conversationId: string, turnId: string): Promise<boolean> {
385→    return this.serialize(async () => {
386→      const data = await this.getFromStorage();
387→
388→      if (data.messages[conversationId]) {
389→        const initialLength = data.messages[conversationId].length;
390→        data.messages[conversationId] = data.messages[conversationId].filter(
391→          (m) => m.turnId !== turnId,
392→        );
393→
394→        if (data.messages[conversationId].length < initialLength) {
395→          // Remove conversation key if no messages left
396→          if (data.messages[conversationId].length === 0) {
397→            delete data.messages[conversationId];
398→          }
399→
400→          await this.saveToStorage(data);
401→          return true;
402→        }
403→      }
404→      return false;
405→    });
406→  }
407→
408→  async getAllStarredMessages(): Promise<StarredMessagesData> {
409→    return this.getFromStorage();
410→  }
411→
412→  async getStarredMessagesForConversation(conversationId: string): Promise<StarredMessage[]> {
413→    const data = await this.getFromStorage();
414→    return data.messages[conversationId] || [];
415→  }
416→
417→  async isMessageStarred(conversationId: string, turnId: string): Promise<boolean> {
418→    const messages = await this.getStarredMessagesForConversation(conversationId);
419→    return messages.some((m) => m.turnId === turnId);
420→  }
421→}
