425→/**
426→ * Centralized fork nodes management to prevent race conditions.
427→ * All read-modify-write operations are serialized through this background script.
428→ */
429→class ForkNodesManager {
430→  private operationQueue: Promise<unknown> = Promise.resolve();
431→
432→  private serialize<T>(operation: () => Promise<T>): Promise<T> {
433→    const promise = this.operationQueue.then(operation, operation);
434→    this.operationQueue = promise.catch(() => {});
435→    return promise;
436→  }
437→
438→  private async getFromStorage(): Promise<ForkNodesData> {
439→    try {
440→      const result = await chrome.storage.local.get([StorageKeys.FORK_NODES]);
441→      return result[StorageKeys.FORK_NODES] || { nodes: {}, groups: {} };
442→    } catch (error) {
443→      console.error('[Background] Failed to get fork nodes:', error);
444→      return { nodes: {}, groups: {} };
445→    }
446→  }
447→
448→  private async saveToStorage(data: ForkNodesData): Promise<void> {
449→    await chrome.storage.local.set({ [StorageKeys.FORK_NODES]: data });
450→  }
451→
452→  async addForkNode(node: ForkNode): Promise<boolean> {
453→    return this.serialize(async () => {
454→      const data = await this.getFromStorage();
455→
456→      if (!data.nodes[node.conversationId]) {
457→        data.nodes[node.conversationId] = [];
458→      }
459→
460→      const exists = data.nodes[node.conversationId].some(
461→        (n) => n.turnId === node.turnId && n.forkGroupId === node.forkGroupId,
462→      );
463→
464→      if (!exists) {
465→        data.nodes[node.conversationId].push(node);
466→
467→        // Update group index
468→        if (!data.groups[node.forkGroupId]) {
469→          data.groups[node.forkGroupId] = [];
470→        }
471→        const groupKey = `${node.conversationId}:${node.turnId}`;
472→        if (!data.groups[node.forkGroupId].includes(groupKey)) {
473→          data.groups[node.forkGroupId].push(groupKey);
474→        }
475→
476→        await this.saveToStorage(data);
477→        return true;
478→      }
479→      return false;
480→    });
481→  }
482→
483→  async removeForkNode(
484→    conversationId: string,
485→    turnId: string,
486→    forkGroupId: string,
487→  ): Promise<boolean> {
488→    return this.serialize(async () => {
489→      const data = await this.getFromStorage();
490→
491→      if (data.nodes[conversationId]) {
492→        const initialLength = data.nodes[conversationId].length;
493→        data.nodes[conversationId] = data.nodes[conversationId].filter(
494→          (n) => !(n.turnId === turnId && n.forkGroupId === forkGroupId),
495→        );
496→
497→        if (data.nodes[conversationId].length < initialLength) {
498→          if (data.nodes[conversationId].length === 0) {
499→            delete data.nodes[conversationId];
500→          }
501→
502→          // Update group index
503→          if (data.groups[forkGroupId]) {
504→            const groupKey = `${conversationId}:${turnId}`;
505→            data.groups[forkGroupId] = data.groups[forkGroupId].filter((k) => k !== groupKey);
506→            if (data.groups[forkGroupId].length === 0) {
507→              delete data.groups[forkGroupId];
508→            }
509→          }
510→
511→          await this.saveToStorage(data);
512→          return true;
513→        }
514→      }
515→      return false;
516→    });
517→  }
518→
519→  async getAllForkNodes(): Promise<ForkNodesData> {
520→    return this.getFromStorage();
521→  }
522→
523→  async getForConversation(conversationId: string): Promise<ForkNode[]> {
524→    const data = await this.getFromStorage();
525→    return data.nodes[conversationId] || [];
526→  }
527→
528→  async getGroup(forkGroupId: string): Promise<ForkNode[]> {
529→    const data = await this.getFromStorage();
530→    const groupKeys = data.groups[forkGroupId] || [];
531→    const nodes: ForkNode[] = [];
532→
533→    for (const key of groupKeys) {
534→      const [convId, turnId] = key.split(':');
535→      const convNodes = data.nodes[convId] || [];
536→      const match = convNodes.find((n) => n.turnId === turnId && n.forkGroupId === forkGroupId);
537→      if (match) nodes.push(match);
538→    }
539→
540→    return nodes.sort((a, b) => a.forkIndex - b.forkIndex);
541→  }
542→}
