 73→/**
 74→ * Detect if the current platform is macOS
 75→ *
 76→ * @returns true if running on macOS
 77→ */
 78→export function isMac(): boolean {
 79→  // navigator.platform is deprecated but still widely supported and reliable
 80→  // Use it first, then fall back to userAgent
 81→  if (typeof navigator !== 'undefined') {
 82→    if (navigator.platform) {
 83→      return navigator.platform.toUpperCase().includes('MAC');
 84→    }
 85→    return /macintosh|mac os x/i.test(navigator.userAgent);
 86→  }
 87→  return false;
 88→}
