 90→/**
 91→ * Get the platform-appropriate modifier key label
 92→ * macOS: ⌘ (Cmd), others: Ctrl
 93→ *
 94→ * @returns '⌘' on macOS, 'Ctrl' on other platforms
 95→ */
 96→export function getModifierKey(): string {
 97→  return isMac() ? '⌘' : 'Ctrl';
 98→}
