100→/**
101→ * Get browser name for debugging
102→ * Uses user agent detection for reliability
103→ */
104→export function getBrowserName(): string {
105→  if (isSafari()) return 'Safari';
106→
107→  if (isFirefox()) return 'Firefox';
108→
109→  const ua = navigator.userAgent.toLowerCase();
110→
111→  // Chrome/Edge/Brave have 'chrome' or 'chromium' in UA
112→  if (ua.includes('chrome') || ua.includes('chromium')) {
113→    if (ua.includes('edg')) return 'Edge';
114→    return 'Chrome/Chromium';
115→  }
116→
117→  return 'Unknown';
118→}
