577→function showForkConfirmation(btn: HTMLElement, userEl: HTMLElement, turnIndex: number): void {
578→  dismissConfirm();
579→
580→  const confirm = document.createElement('div');
581→  confirm.className = FORK_CONFIRM_CLASS;
582→  confirm.innerHTML = `
583→    <p>${getTranslationSync('forkConfirm')}</p>
584→    <div class="gv-fork-actions">
585→      <button class="gv-fork-cancel">${getTranslationSync('forkCancel')}</button>
586→      <button class="gv-fork-primary">${getTranslationSync('forkConfirmBtn')}</button>
587→    </div>
588→  `;
589→
590→  const cancelBtn = confirm.querySelector('.gv-fork-cancel')!;
591→  const confirmBtn = confirm.querySelector('.gv-fork-primary')!;
592→
593→  cancelBtn.addEventListener('click', (e) => {
594→    e.stopPropagation();
595→    e.preventDefault();
596→    dismissConfirm();
597→  });
598→  confirmBtn.addEventListener('click', (e) => {
599→    e.stopPropagation();
600→    e.preventDefault();
601→    dismissConfirm();
602→    void executeFork(userEl, turnIndex);
603→  });
604→
605→  // Prevent clicks inside the dialog from bubbling to parent handlers
606→  confirm.addEventListener('click', (e) => e.stopPropagation());
607→
608→  // Position near the fork button using fixed positioning
609→  const btnRect = btn.getBoundingClientRect();
610→  confirm.style.position = 'fixed';
611→  confirm.style.top = `${btnRect.top - 4}px`;
612→  confirm.style.left = `${btnRect.right}px`;
613→  confirm.style.transform = 'translateY(-100%)';
614→
615→  document.body.appendChild(confirm);
616→  activeConfirm = confirm;
617→}
