619→async function executeFork(userEl: HTMLElement, turnIndex: number): Promise<void> {
620→  const conversationId = extractConversationIdFromUrl();
621→  if (!conversationId) {
622→    console.warn('[Fork] No conversation ID found');
623→    return;
624→  }
625→
626→  const turnId = ensureTurnId(userEl, turnIndex);
627→  const markdown = extractConversationUpToTurn(turnIndex, turnId);
628→  if (!markdown.trim()) {
629→    console.warn('[Fork] No content extracted');
630→    return;
631→  }
632→  const preferredLanguage = await getPreferredLanguage();
633→  const markdownWithContext = composeForkInputWithContext(markdown, preferredLanguage);
634→
635→  let forkGroupId = generateUniqueId('fork');
636→  let sourceForkIndex = 0;
637→  let nextForkIndex = 1;
638→
639→  try {
640→    const conversationNodes = await ForkNodesService.getForConversation(conversationId);
641→    const candidateGroupIds = Array.from(
642→      new Set(
643→        conversationNodes
644→          .filter((node) => normalizeTurnId(node.turnId) === normalizeTurnId(turnId))
645→          .map((node) => node.forkGroupId),
646→      ),
647→    );
648→
649→    const groups: Record<string, ForkNode[]> = {};
650→    for (const groupId of candidateGroupIds) {
651→      groups[groupId] = await ForkNodesService.getGroup(groupId);
652→    }
653→
654→    const plan = resolveForkPlan(conversationId, turnId, conversationNodes, groups, () =>
655→      generateUniqueId('fork'),
656→    );
657→
658→    forkGroupId = plan.forkGroupId;
659→    sourceForkIndex = plan.sourceForkIndex;
660→    nextForkIndex = plan.nextForkIndex;
661→  } catch (error) {
662→    if (!isExtensionContextInvalidatedError(error)) {
663→      console.error('[Fork] Failed to resolve fork group, using default:', error);
664→    }
665→  }
